select 
from im_private_message
where conversation_id = #{conversationId}
  and from_user_id = #{fromUserId, jdbcType=BINARY}
  and client_msg_id = #{clientMsgId}

select 
from im_private_message
where conversation_id = #{conversationId}
  and seq > #{afterSeqExclusive}
order by seq asc
limit #{limit}
